import * as React from 'react';
import { createComponent } from '../create-component.js';
import Component from '../../components/divider/src/divider.component.js';
const tagName = 'made-divider';
Component.define('made-divider');
/**
 * @summary A divider is a thin line that visually separates or groups elements.
 * @documentation '../../components/divider/stories/divider.mdx'
 *
 * @documentation
 *
 * @cssproperty --color - The color of the line.
 * @cssproperty --thickness - The thickness of the line.
 * @cssproperty --inset - The amount of padding apllied when divider is inset.
 */
const reactWrapper = createComponent({
    tagName,
    elementClass: Component,
    react: React,
    events: {},
    displayName: 'MadeDivider'
});
export default reactWrapper;
